args.sparql:
SELECT ?athlete (COUNT(*) AS ?medalCount)
WHERE {
  wd:Q9583 wdt:P527 ?event .
  ?event p:P1346 [ ps:P1346 ?athlete; pq:P1062 ?medal ] .
  VALUES ?medalType { wd:Q164757 wd:Q11731 wd:Q3151297 }
  FILTER (?medal IN (?medalType))
}
GROUP BY ?athlete
ORDER BY DESC(?medalCount)
LIMIT 1

SELECT ?athlete (COUNT(*) AS ?medalCount)
WHERE {
  wd:Q9583 wdt:P527 ?event .
  ?event p:P1346 [ ps:P1346 ?athlete; pq:P1062 ?medal ] .
  VALUES ?medal { wd:Q164757 wd:Q11731 wd:Q3151297 }
  FILTER (ISBLANK(?medal) = false)
}
GROUP BY ?athlete
ORDER BY DESC(?medalCount)
LIMIT 1
